SELECT COUNT(*)
FROM HOLDINGS
WHERE USER_ID = #{userId}
AND STOCK_ID = #{stockId}

SELECT *
FROM HOLDINGS
WHERE USER_ID = #{userId}
AND STOCK_ID = #{stockId}

mapper.update:
UPDATE HOLDINGS
SET TOTAL_PRICE = TOTAL_PRICE + #{totalTradePrice},
    TOTAL_COUNT = TOTAL_COUNT + #{tradeCount}
WHERE USER_ID = #{userId}
AND STOCK_ID = #{stockId}

UPDATE HOLDINGS
SET TOTAL_PRICE = TOTAL_PRICE - #{totalTradePrice},
    TOTAL_COUNT = TOTAL_COUNT - #{tradeCount}
WHERE USER_ID = #{userId}
AND STOCK_ID = #{stockId}

mapper.delete:
DELETE FROM HOLDINGS
WHERE USER_ID = #{userId}
AND STOCK_ID = #{stockId}

